fetch_casting_name_on_mount.body:
    let savedToken = localStorage.getItem('dlms_auth_token');

if (!savedToken) {
    return;
}

let requestBody = {
    "fields": [
        "data.main.data._id",
        "data.main.data.casting_name"
    ],
    "search_fields": [],
    "search": "",
    "status": "completed",
    "limit": 100
};

try {
    const res = await fetch('https://dlms-api-stage.iotnp.com/api/v1/templates/casting_master/dropdown/v2', {
        method: 'POST',
        headers: {
            'accept': 'application/json',
            'Content-Type': 'application/json',
            'Authorization': `Bearer ${savedToken}`
        },
        body: JSON.stringify(requestBody)
    });

    if (!res.ok) {
        return;
    }

    const response = await res.json();
    const items = Array.isArray(response.data) ? response.data : [];

    window._castingDataLookup = new Map();

    const preparedData = items.map(item => {
        const id = item._id || "";
        const castingName = item["data.main.data.casting_name"] || "";

        window._castingDataLookup.set(id, {
            _id: id,
            casting_name: castingName
        });

        return {
            value: castingName,
            label: castingName,
            data: {
                _id: id,
                casting_name: castingName
            }
        };
    });

    if (e.setUserDefinedProps) {
        e.setUserDefinedProps({ data: preparedData });
    }

} catch (err) {
    console.error("Fetch error:", err);
}

on_select_casting_name.body:
const selectedValues = e.args[0] || [];

// Clear all previous data (up to 10 parts)
for (let i = 0; i < 10; i++) {
    e.data[`parts__${i}__casting_name`] = "";
    e.data[`parts__${i}__id`] = "";
    e.data[`parts__${i}__limit`] = "";
}
e.data.meta__parts_count = 0;
e.data.castings = []; // Initialize empty array

console.log("Selected values:", selectedValues);

if (selectedValues.length === 0) {
    return;
}

// Since value is castingName, we need to find by casting_name
// Create a reverse lookup by casting_name
const castingByName = new Map();
if (window._castingDataLookup) {
    window._castingDataLookup.forEach((data, id) => {
        castingByName.set(data.casting_name, data);
    });
}

// Build the castings array
const castingsArray = [];

// Populate parts based on selection
let partIndex = 0;
selectedValues.forEach(castingName => {
    if (partIndex < 10) {
        const data = castingByName.get(castingName);
        if (data) {
            e.data[`parts__${partIndex}__casting_name`] = data.casting_name || castingName;
            e.data[`parts__${partIndex}__id`] = data._id || "";

            // Add to castings array
            castingsArray.push({
                id: data._id || "",
                value: data.casting_name || castingName
            });
        } else {
            // If not found in lookup, use the castingName directly
            e.data[`parts__${partIndex}__casting_name`] = castingName;
            e.data[`parts__${partIndex}__id`] = "";

            // Add to castings array
            castingsArray.push({
                id: "",
                value: castingName
            });
        }
        partIndex++;
    }
});

// Set the castings array in e.data
e.data.castings = castingsArray;
e.data.meta__parts_count = selectedValues.length;

console.log("Parts populated:", {
    partsCount: selectedValues.length,
    selectedNames: selectedValues,
    castings: castingsArray
});

on_change_casting_selection.body:
const selectedValues = e.args[0] || [];

// Clear all previous data (up to 10 parts)
for (let i = 0; i <= 10; i++) {
    e.data[`parts__${i}__casting_name`] = "";
    e.data[`parts__${i}__id`] = "";
    e.data[`parts__${i}__limit`] = "";
}
e.data.meta__parts_count = 0;

if (selectedValues.length === 0) {
    return;
}

// Create reverse lookup by casting_name
const castingByName = new Map();
if (window._castingDataLookup) {
    window._castingDataLookup.forEach((data, id) => {
        castingByName.set(data.casting_name, data);
    });
}

// Populate parts based on current selection
let partIndex = 0;
selectedValues.forEach(castingName => {
    if (partIndex <= 10) {
        const data = castingByName.get(castingName);
        if (data) {
            e.data[`parts__${partIndex}__casting_name`] = data.casting_name || castingName;
            e.data[`parts__${partIndex}__id`] = data._id || "";
        } else {
            e.data[`parts__${partIndex}__casting_name`] = castingName;
            e.data[`parts_${partIndex}__id`] = "";
        }
        partIndex++;
    }
});

e.data.meta__parts_count = selectedValues.length;

on_clean_casting_selection.body:
for (let i = 1; i <= 10; i++) {
        e.data[`parts__${i}__casting_name`] = "";
        e.data[`parts__${i}__id`] = "";
        e.data[`parts__${i}__limit`] = "";
    }
    e.data.meta__parts_count = 0;

