const errors = {};
const MAX_ROWS = 5, MAX_COLS = 6;
const isEmpty = v => !v || String(v).trim() === "";

// Parts validation
for (let i = 0; i < 10; i++) {
    if (!isEmpty(formData[`parts__${i}__casting_name`]) && isEmpty(formData[`parts__${i}__limit`])) {
        errors[`parts__${i}__limit`] = "Limit is required";
    }
}

// Load Test Specs validation
// Only trigger validation when a cell VALUE exists (not just headers)
for (let r = 0; r < MAX_ROWS; r++) {
    for (let c = 0; c < MAX_COLS; c++) {
        const cellValue = formData[`lt__${r}__${c}__val`];

        // Only validate if this cell has a value entered
        if (!isEmpty(cellValue)) {
            // Require param header for this row
            if (isEmpty(formData[`lt__param_${r}`]) && !errors[`lt__param_${r}`]) {
                errors[`lt__param_${r}`] = "Parameter is required";
            }
            // Require spec header for this column
            if (isEmpty(formData[`lt__spec_${c}`]) && !errors[`lt__spec_${c}`]) {
                errors[`lt__spec_${c}`] = "Spec is required";
            }

            // Require Value for this cell
            if (isEmpty(formData[`lt__${r}__${c}__val`])) {
                errors[`lt__${r}__${c}__val`] = "Required";
            }

            // Require tolerances for this cell
            if (isEmpty(formData[`lt__${r}__${c}__minus`])) {
                errors[`lt__${r}__${c}__minus`] = "Required";
            }
            if (isEmpty(formData[`lt__${r}__${c}__plus`])) {
                errors[`lt__${r}__${c}__plus`] = "Required";
            }
        }
    }
}

return Object.keys(errors).length > 0 ? errors : undefined;

